// Enterprise-grade code intelligence structures
struct SymbolInfo {
    QString name;
    QString type; // "function", "class", "variable", "namespace", etc.
    QString filePath;
    int lineNumber;
    int columnNumber;
    QString signature;
    QString documentation;
