    QString returnType;
    QString visibility; // "public", "private", "protected", "internal"
    bool isStatic = false;
    bool isVirtual = false;
    bool isPureVirtual = false;
    bool isConst = false;
    QString parentClass;
    QVector<QString> baseClasses;
    QVector<QString> derivedClasses;
    QJsonObject metadata;
};

struct DependencyInfo {
    QString fromSymbol;
    QString toSymbol;
    QString dependencyType; // "import", "inheritance", "composition", "usage"
    QString filePath;
    int lineNumber;
    double confidence; // 0.0 to 1.0
    QJsonObject context;
};

struct ArchitecturePattern {
    QString patternType; // "MVC", "MVVM", "Microservice", "Layered", "Monolith"
    double confidenceScore;
    QJsonArray evidence;
    QVector<QString> affectedFiles;
