bool IntelligentCodebaseEngine::analyzeFile(const QString& filePath) {
    std::cout << "[IntelligentCodebaseEngine] Analyzing file: " << filePath.toStdString() << std::endl;
    
    QFile file(filePath);
    if (!file.open(QIODevice::ReadOnly | QIODevice::Text)) {
        return false;
    }
    
    QTextStream stream(&file);
    QString content = stream.readAll();
    file.close();
    
    // Detect file type and language
    QString language = detectLanguage(filePath);
    QString fileType = detectFileType(filePath);
    
    std::cout << "[IntelligentCodebaseEngine] Detected: " << language.toStdString() 
              << " (" << fileType.toStdString() << ")" << std::endl;
    
    // Parse file content based on language
    if (language == "cpp" || language == "c") {
        return analyzeCppFile(filePath, content);
    } else if (language == "python") {
        return analyzePythonFile(filePath, content);
    } else if (language == "javascript" || language == "typescript") {
        return analyzeJavaScriptFile(filePath, content);
    } else if (language == "java") {
        return analyzeJavaFile(filePath, content);
    } else if (language == "rust") {
        return analyzeRustFile(filePath, content);
    } else if (language == "go") {
        return analyzeGoFile(filePath, content);
    }
    
    // Generic analysis for unknown languages
    return analyzeGenericFile(filePath, content);
}

bool IntelligentCodebaseEngine::analyzeCppFile(const QString& filePath, const QString& content) {
    // C++ specific analysis with enterprise-grade parsing
    
    // Function detection with signatures
    QRegularExpression functionRegex(R"((\w+(?:\s*\*)?\s+)(\w+)\s*\(([^)]*)\)\s*(const)?\s*(?:->\s*(\w+))?\s*\{)");
    QRegularExpressionMatchIterator functionMatches = functionRegex.globalMatch(content);
    
    while (functionMatches.hasNext()) {
        QRegularExpressionMatch match = functionMatches.next();
        
        SymbolInfo function;
        function.name = match.captured(2);
        function.type = "function";
        function.filePath = filePath;
        function.signature = match.captured(0);
        function.returnType = match.captured(1).trimmed();
        function.parameters = parseParameters(match.captured(3));
        function.isConst = !match.captured(4).isEmpty();
        
        // Enhanced analysis
        function.metadata["language"] = "cpp";
        function.metadata["signature"] = match.captured(0);
        function.metadata["parameters"] = QJsonArray::fromStringList(function.parameters);
        
        // Add to index
        symbolIndex[function.name] = function;
        fileSymbols[filePath].append(function);
        symbolByName[function.name] = function;
        
        std::cout << "[IntelligentCodebaseEngine] Found function: " << function.name.toStdString() 
                  << " (" << function.returnType.toStdString() << ")" << std::endl;
    }
    
    // Class detection with inheritance
    QRegularExpression classRegex(R"(class\s+(\w+)\s*(?::\s*(?:public|private|protected)\s+(\w+))?\s*\{)");
    QRegularExpressionMatchIterator classMatches = classRegex.globalMatch(content);
    
    while (classMatches.hasNext()) {
        QRegularExpressionMatch match = classMatches.next();
        
        SymbolInfo classSymbol;
        classSymbol.name = match.captured(1);
        classSymbol.type = "class";
        classSymbol.filePath = filePath;
        classSignature.signature = match.captured(0);
        
        if (!match.captured(2).isEmpty()) {
            classSymbol.baseClasses.append(match.captured(2));
        }
        
        // Build inheritance hierarchy
        for (const QString& baseClass : classSymbol.baseClasses) {
            inheritanceHierarchy[classSymbol.name].append(baseClass);
        }
        
        symbolIndex[classSymbol.name] = classSymbol;
        fileSymbols[filePath].append(classSymbol);
        
        std::cout << "[IntelligentCodebaseEngine] Found class: " << classSymbol.name.toStdString() << std::endl;
    }
    
    // Variable and constant detection
    QRegularExpression variableRegex(R"((const\s+)?(\w+(?:\s*\*)?)\s+(\w+)\s*(?:=\s*([^;]+))?;)");
    QRegularExpressionMatchIterator variableMatches = variableRegex.globalMatch(content);
    
    while (variableMatches.hasNext()) {
        QRegularExpressionMatch match = variableMatches.next();
        
        SymbolInfo variable;
        variable.name = match.captured(3);
        variable.type = match.captured(1).isEmpty() ? "variable" : "constant";
        variable.filePath = filePath;
        variable.returnType = match.captured(2).trimmed();
        variable.isConst = !match.captured(1).isEmpty();
        
        if (!match.captured(4).isEmpty()) {
            variable.metadata["initializer"] = match.captured(4);
        }
        
        symbolIndex[variable.name] = variable;
        fileSymbols[filePath].append(variable);
    }
    
    // Namespace detection
    QRegularExpression namespaceRegex(R"(namespace\s+(\w+)\s*\{)");
    QRegularExpressionMatchIterator namespaceMatches = namespaceRegex.globalMatch(content);
    
    while (namespaceMatches.hasNext()) {
        QRegularExpressionMatch match = namespaceMatches.next();
        
        SymbolInfo namespaceSymbol;
        namespaceSymbol.name = match.captured(1);
        namespaceSymbol.type = "namespace";
        namespaceSymbol.filePath = filePath;
        
        symbolIndex[namespaceSymbol.name] = namespaceSymbol;
        fileSymbols[filePath].append(namespaceSymbol);
    }
    
    // Call graph analysis
    analyzeCallGraph(filePath, content);
    
    // Dependency analysis
    analyzeDependencies(filePath, content);
    
    // Complexity analysis
    analyzeComplexity(filePath, content);
    
    return true;
}

bool IntelligentCodebaseEngine::analyzeCallGraph(const QString& filePath, const QString& content) {
    // Analyze function calls to build call hierarchy
    
    QRegularExpression callRegex(R"(\b(\w+)\s*\()");
    QRegularExpressionMatchIterator callMatches = callRegex.globalMatch(content);
    
    while (callMatches.hasNext()) {
        QRegularExpressionMatch match = callMatches.next();
        QString calledFunction = match.captured(1);
        
        // Skip common non-function calls
        if (calledFunction == "if" || calledFunction == "while" || 
            calledFunction == "for" || calledFunction == "switch") {
            continue;
        }
        
        // Add to call graph (would need current function context)
        if (symbolIndex.contains(calledFunction)) {
            callGraph[calledFunction].append("current_function"); // Would be actual caller
        }
    }
    
    return true;
}

bool IntelligentCodebaseEngine::analyzeDependencies(const QString& filePath, const QString& content) {
    // Analyze import/include dependencies
    
    // C++ includes
    QRegularExpression includeRegex(R"(#include\s*["<]([^">]+)[">])");
    QRegularExpressionMatchIterator includeMatches = includeRegex.globalMatch(content);
    
    while (includeMatches.hasNext()) {
        QRegularExpressionMatch match = includeMatches.next();
        QString includeFile = match.captured(1);
        
        DependencyInfo dependency;
        dependency.fromSymbol = filePath; // Current file
        dependency.toSymbol = includeFile;
        dependency.dependencyType = "import";
        dependency.filePath = filePath;
        dependency.lineNumber = match.capturedStart();
        dependency.confidence = 0.95; // High confidence for explicit includes
        
        dependencyGraph[filePath].append(dependency);
    }
    
    // Namespace usage
    QRegularExpression namespaceUsageRegex(R"(\b(\w+)::(\w+)\b)");
    QRegularExpressionMatchIterator namespaceMatches = namespaceUsageRegex.globalMatch(content);
    
    while (namespaceMatches.hasNext()) {
        QRegularExpressionMatch match = namespaceMatches.next();
        QString namespaceName = match.captured(1);
        QString symbolName = match.captured(2);
        
        DependencyInfo dependency;
        dependency.fromSymbol = "current_context"; // Would be actual context
        dependency.toSymbol = namespaceName + "::" + symbolName;
        dependency.dependencyType = "usage";
        dependency.filePath = filePath;
        dependency.lineNumber = match.capturedStart();
        dependency.confidence = 0.9;
        
        dependencyGraph[filePath].append(dependency);
    }
    
    return true;
}

bool IntelligentCodebaseEngine::analyzeComplexity(const QString& filePath, const QString& content) {
    // Calculate various complexity metrics
    
    int totalLines = content.count('\n') + 1;
    int codeLines = 0;
    int commentLines = 0;
    int blankLines = 0;
    
    QStringList lines = content.split('\n');
    for (const QString& line : lines) {
        QString trimmed = line.trimmed();
        if (trimmed.isEmpty()) {
            blankLines++;
        } else if (trimmed.startsWith("//") || trimmed.startsWith("/*") || trimmed.startsWith("*")) {
            commentLines++;
        } else {
            codeLines++;
        }
    }
    
    // Cyclomatic complexity (simplified)
    QRegularExpression branchRegex(R"(\b(if|while|for|switch|case|catch)\b)");
    int branchCount = branchRegex.globalMatch(content).count();
    
    // Function complexity
    int functionCount = fileSymbols[filePath].size();
    
    CodeComplexity& complexity = complexityAnalysis;
    complexity.linesOfCode = codeLines;
    complexity.cyclomaticComplexity = branchCount + 1; // +1 for base complexity
    complexity.numberOfFunctions = functionCount;
    
    // Detect complexity hotspots
    for (const SymbolInfo& symbol : fileSymbols[filePath]) {
        if (symbol.type == "function") {
            double functionComplexity = calculateFunctionComplexity(symbol);
            if (functionComplexity > 10) { // High complexity threshold
                complexity.complexityHotspots.append(QJsonObject{
                    {"symbol", symbol.name},
                    {"complexity", functionComplexity},
                    {"type", "function"}
                });
            }
        }
    }
    
    return true;
}

double IntelligentCodebaseEngine::calculateFunctionComplexity(const SymbolInfo& function) {
    // Simplified complexity calculation
    // Would be enhanced with actual control flow analysis
    
    double complexity = 1.0; // Base complexity
    
    // Add complexity for parameters
    complexity += function.parameters.size() * 0.5;
    
    // Add complexity for const/static modifiers
    if (function.isStatic) complexity += 0.5;
    if (function.isConst) complexity += 0.3;
    
    // Add complexity for inheritance
    complexity += function.baseClasses.size() * 0.8;
    
    return complexity;
}

