ArchitecturePattern IntelligentCodebaseEngine::detectArchitecturePattern() {
    std::cout << "[IntelligentCodebaseEngine] Detecting architecture patterns..." << std::endl;
    
    ArchitecturePattern pattern;
    pattern.confidenceScore = 0.0;
    
    // MVC Pattern Detection
    bool hasModels = false;
    bool hasViews = false;
    bool hasControllers = false;
    
    for (auto it = symbolIndex.begin(); it != symbolIndex.end(); ++it) {
        const SymbolInfo& symbol = it.value();
        
        if (symbol.type == "class") {
            QString className = symbol.name.toLower();
            
            if (className.contains("model") || className.contains("entity")) {
                hasModels = true;
            } else if (className.contains("view") || className.contains("widget")) {
                hasViews = true;
            } else if (className.contains("controller") || className.contains("manager")) {
                hasControllers = true;
            }
        }
    }
    
    if (hasModels && hasViews && hasControllers) {
        pattern.patternType = "MVC";
        pattern.confidenceScore = 0.85;
        
        QJsonObject characteristics;
        characteristics["has_models"] = hasModels;
        characteristics["has_views"] = hasViews;
        characteristics["has_controllers"] = hasControllers;
        pattern.characteristics = characteristics;
        
        pattern.evidence.append("Model classes detected");
        pattern.evidence.append("View classes detected");
        pattern.evidence.append("Controller classes detected");
        
        for (auto it = symbolIndex.begin(); it != symbolIndex.end(); ++it) {
            const SymbolInfo& symbol = it.value();
            if (symbol.type == "class") {
                QString className = symbol.name.toLower();
                if (className.contains("model") || className.contains("view") || className.contains("controller")) {
                    pattern.affectedFiles.append(symbol.filePath);
                }
            }
        }
    }
    
    // Microservice Pattern Detection
    bool hasMultipleServices = false;
    bool hasAPIEndpoints = false;
    bool hasIndependentDeployment = false;
    
    int serviceCount = 0;
    for (auto it = symbolIndex.begin(); it != symbolIndex.end(); ++it) {
        const SymbolInfo& symbol = it.value();
        if (symbol.type == "class") {
            QString className = symbol.name.toLower();
            if (className.contains("service") || className.contains("api")) {
                serviceCount++;
            }
        }
    }
    
    if (serviceCount > 5) { // Multiple services detected
        hasMultipleServices = true;
        
        // Check for API patterns
        for (auto it = symbolIndex.begin(); it != symbolIndex.end(); ++it) {
            const SymbolInfo& symbol = it.value();
            if (symbol.type == "function") {
                QString functionName = symbol.name.toLower();
                if (functionName.contains("api") || functionName.contains("endpoint")) {
                    hasAPIEndpoints = true;
                    break;
                }
            }
        }
    }
    
    if (hasMultipleServices && hasAPIEndpoints) {
        pattern.patternType = "Microservice";
        pattern.confidenceScore = 0.75;
        
        QJsonObject characteristics;
        characteristics["multiple_services"] = hasMultipleServices;
        characteristics["api_endpoints"] = hasAPIEndpoints;
        characteristics["service_count"] = serviceCount;
        pattern.characteristics = characteristics;
        
        pattern.evidence.append("Multiple service classes detected");
        pattern.evidence.append("API endpoint patterns found");
        
        for (auto it = symbolIndex.begin(); it != symbolIndex.end(); ++it) {
            const SymbolInfo& symbol = it.value();
            if (symbol.type == "class") {
                QString className = symbol.name.toLower();
                if (className.contains("service") || className.contains("api")) {
                    pattern.affectedFiles.append(symbol.filePath);
                }
            }
        }
    }
    
    // Layered Architecture Detection
    bool hasPresentation = false;
    bool hasBusinessLogic = false;
    bool hasDataAccess = false;
    
    for (auto it = symbolIndex.begin(); it != symbolIndex.end(); ++it) {
        const SymbolInfo& symbol = it.value();
        if (symbol.type == "class") {
            QString className = symbol.name.toLower();
            
            if (className.contains("ui") || className.contains("view") || className.contains("presentation")) {
                hasPresentation = true;
            } else if (className.contains("business") || className.contains("service") || className.contains("logic")) {
                hasBusinessLogic = true;
            } else if (className.contains("data") || className.contains("repository") || className.contains("dao")) {
                hasDataAccess = true;
            }
        }
    }
    
    if (hasPresentation && hasBusinessLogic && hasDataAccess) {
        pattern.patternType = "Layered";
        pattern.confidenceScore = 0.8;
        
        QJsonObject characteristics;
        characteristics["presentation_layer"] = hasPresentation;
        characteristics["business_logic_layer"] = hasBusinessLogic;
        characteristics["data_access_layer"] = hasDataAccess;
        pattern.characteristics = characteristics;
        
        pattern.evidence.append("Presentation layer detected");
        pattern.evidence.append("Business logic layer detected");
        pattern.evidence.append("Data access layer detected");
        
        for (auto it = symbolIndex.begin(); it != symbolIndex.end(); ++it) {
            const SymbolInfo& symbol = it.value();
            if (symbol.type == "class") {
                QString className = symbol.name.toLower();
                if (className.contains("ui") || className.contains("business") || className.contains("data")) {
                    pattern.affectedFiles.append(symbol.filePath);
                }
            }
        }
    }
    
    emit architecturePatternDetected(pattern);
    
    return pattern;
}

double IntelligentCodebaseEngine::calculateCodeQualityScore() {
    double score = 1.0; // Start with perfect score
    
    // Reduce score for complexity issues
    for (const RefactoringOpportunity& opportunity : refactoringOpportunities) {
        score -= (1.0 - opportunity.confidence) * 0.1;
    }
    
    // Reduce score for bugs
    for (const BugReport& bug : bugReports) {
        if (bug.severity == "critical") {
            score -= 0.2;
        } else if (bug.severity == "high") {
            score -= 0.1;
        } else if (bug.severity == "medium") {
            score -= 0.05;
        }
    }
    
    // Reduce score for high complexity
    score -= (complexityAnalysis.cyclomaticComplexity / 100.0) * 0.2;
    score -= (complexityAnalysis.duplicationPercentage / 100.0) * 0.15;
    
    return qMax(0.0, qMin(1.0, score));
}

QJsonObject IntelligentCodebaseEngine::generateAnalysisResults() {
    QJsonObject results;
    
    results["symbols_analyzed"] = symbolIndex.size();
    results["files_analyzed"] = fileSymbols.size();
    results["dependencies_found"] = dependencyGraph.size();
    results["refactoring_opportunities"] = refactoringOpportunities.size();
    results["bugs_detected"] = bugReports.size();
    results["optimizations_suggested"] = optimizations.size();
    results["architecture_pattern"] = detectArchitecturePattern().patternType;
    results["code_quality_score"] = calculateCodeQualityScore();
    
    QJsonArray opportunities;
    for (const RefactoringOpportunity& opp : refactoringOpportunities) {
        QJsonObject obj;
        obj["type"] = opp.type;
        obj["description"] = opp.description;
        obj["file_path"] = opp.filePath;
        obj["confidence"] = opp.confidence;
        obj["estimated_impact"] = opp.estimatedImpact;
        opportunities.append(obj);
    }
    results["refactoring_opportunities"] = opportunities;
    
    QJsonArray bugs;
    for (const BugReport& bug : bugReports) {
        QJsonObject obj;
        obj["type"] = bug.bugType;
        obj["severity"] = bug.severity;
        obj["description"] = bug.description;
        obj["file_path"] = bug.filePath;
        obj["confidence"] = bug.confidence;
        bugs.append(obj);
    }
    results["bugs_detected"] = bugs;
    
    QJsonArray optimizations;
    for (const Optimization& opt : optimizations) {
        QJsonObject obj;
        obj["type"] = opt.optimizationType;
        obj["description"] = opt.description;
        obj["potential_improvement"] = opt.potentialImprovement;
        obj["confidence"] = opt.confidence;
        optimizations.append(obj);
    }
    results["optimizations_suggested"] = optimizations;
    
    return results;
}

bool IntelligentCodebaseEngine::startRealTimeAnalysis(const QString& projectPath) {
    std::cout << "[IntelligentCodebaseEngine] Starting real-time analysis for: " << projectPath.toStdString() << std::endl;
    
    // Set up file system watcher
    QFileSystemWatcher* watcher = new QFileSystemWatcher(this);
    watcher->addPath(projectPath);
    
    connect(watcher, &QFileSystemWatcher::fileChanged, this, &IntelligentCodebaseEngine::updateAnalysis);
    connect(watcher, &QFileSystemWatcher::directoryChanged, this, &IntelligentCodebaseEngine::updateAnalysis);
    
    // Initial analysis
    analyzeEntireCodebase(projectPath);
    
    return true;
}

bool IntelligentCodebaseEngine::updateAnalysis(const QString& filePath) {
    std::cout << "[IntelligentCodebaseEngine] Updating analysis for: " << filePath.toStdString() << std::endl;
    
    // Remove old analysis for this file
    removeFileAnalysis(filePath);
    
    // Re-analyze the file
    analyzeFile(filePath);
    
    // Update dependent analyses
    updateDependentAnalyses(filePath);
    
    emit realTimeAnalysisUpdated(filePath);
    
    return true;
}

void IntelligentCodebaseEngine::removeFileAnalysis(const QString& filePath) {
    // Remove symbols from this file
    auto it = fileSymbols.find(filePath);
    if (it != fileSymbols.end()) {
        for (const SymbolInfo& symbol : it.value()) {
            symbolIndex.remove(symbol.name);
            symbolByName.remove(symbol.name);
        }
        fileSymbols.erase(it);
    }
    
    // Remove dependencies involving this file
    dependencyGraph.remove(filePath);
}

void IntelligentCodebaseEngine::updateDependentAnalyses(const QString& filePath) {
    // Find files that depend on the changed file
    QVector<QString> dependentFiles;
    
    for (auto it = dependencyGraph.begin(); it != dependencyGraph.end(); ++it) {
        for (const DependencyInfo& dep : it.value()) {
            if (dep.toSymbol == filePath || dep.fromSymbol == filePath) {
                dependentFiles.append(it.key());
                break;
            }
        }
    }
    
    // Re-analyze dependent files
    for (const QString& dependentFile : dependentFiles) {
        if (dependentFile != filePath) {
            updateAnalysis(dependentFile);
        }
    }
}

double IntelligentCodebaseEngine::calculateMaintainabilityIndex() {
    // Industry-standard maintainability index calculation
    
    double avgComplexity = 0.0;
    int functionCount = 0;
    
    for (const SymbolInfo& symbol : symbolIndex) {
        if (symbol.type == "function") {
            avgComplexity += calculateFunctionComplexity(symbol);
            functionCount++;
        }
    }
    
    if (functionCount > 0) {
        avgComplexity /= functionCount;
    }
    
    double linesOfCode = complexityAnalysis.linesOfCode;
    double halsteadVolume = calculateHalsteadVolume(); // Would implement full Halstead
    double maintainabilityIndex = 171.0 - 5.2 * log(halsteadVolume) - 0.23 * avgComplexity - 16.2 * log(linesOfCode) + 50.0 * sin(sqrt(2.4 * complexityAnalysis.cognitiveComplexity));
    
    return qMax(0.0, qMin(1.0, maintainabilityIndex / 100.0));
}

